import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import Cookies from "js-cookie";
import { useState, useEffect } from "react";

import PermissionContext from "./context/PermissionContext";
import ProtectedRoute from "./components/ProtectedRoute";

import AdminLogin from "./pages/AdminLogin";
import Dashboard from "./pages/Dashboard";
import MyProfile from "./pages/MyProfile";
import UserManagement from "./pages/UserManagement";
import PaymentsManagement from "./pages/PaymentsManagement";
import EmployeeManagement from "./pages/EmployeeManagement";
import UserDetails from "./pages/UserDetails";
import SupportManagement from "./pages/SupportManagement";
import RoleManagement from "./pages/RoleManagement";
import PermissionManagement from "./pages/PermissionManagement";
import ProtectedLayout from "./layouts/ProtectedLayout";

function App() {
  const [permissions, setPermissions] = useState([]);
  const [permissionsLoaded, setPermissionsLoaded] = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(
    () => !!Cookies.get("adminToken"),
  );

  useEffect(() => {
    const storedPermissions = JSON.parse(localStorage.getItem("permissions"));

    if (storedPermissions && Array.isArray(storedPermissions)) {
      setPermissions(storedPermissions);
    } else {
      setPermissions([]);
    }

    setPermissionsLoaded(true); // ✅ Mark loaded
  }, []);

  function ScrollToTop() {
    const { pathname } = useLocation();
    useEffect(() => {
      window.scrollTo(0, 0);
    }, [pathname]);
    return null;
  }

  // 🔥 Prevent rendering until permissions are ready
  if (!permissionsLoaded) {
    return <div className="text-center mt-5">Loading...</div>;
  }

  return (
    <PermissionContext.Provider
      value={{ permissions, loaded: permissionsLoaded }}
    >
      <BrowserRouter>
        <ScrollToTop />
        <Routes>
          <Route
            path="/"
            element={<AdminLogin setAuth={setIsAuthenticated} />}
          />

          <Route element={<ProtectedLayout />}>
            <Route
              path="/dashboard"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <Dashboard />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/myprofile"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <MyProfile />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/users"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <UserManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/users/:userId"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <UserDetails />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/payment"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <PaymentsManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/support"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <SupportManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/employee"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <EmployeeManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/roles"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <RoleManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/permissions"
              element={
                isAuthenticated ? (
                  <ProtectedRoute>
                    <PermissionManagement />
                  </ProtectedRoute>
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />
          </Route>

          <Route path="*" element={<div>404 - Page not found</div>} />
        </Routes>
      </BrowserRouter>
    </PermissionContext.Provider>
  );
}

export default App;
